import type Collection from "../../core/Collection.js";
import type Polygon from "../../geometry/Polygon.js";
import type { JSONSupport } from "../../core/JSONSupport.js";
import type { PolygonProperties } from "../../geometry/Polygon.js";
import type { ReadonlyArrayOrCollection } from "../../core/Collection.js";

export interface SceneFilterProperties extends Partial<Pick<SceneFilter, "spatialRelationship">> {
  /**
   * The geometries to apply to the spatial filter.
   *
   * The spatial relationship as specified by [spatialRelationship](https://developers.arcgis.com/javascript/latest/references/core/layers/support/SceneFilter/#spatialRelationship) will indicate how the
   * geometry should be used to filter features. Multiple, overlapping geometries are applied as the union of their
   * spatialRelationship operation. For multiple rings within a polygon the even odd rule is used to determine whether
   * a point is inside.
   *
   * > [!WARNING]
   * >
   * > **Known Limitations**
   * >
   * > [Polygon](https://developers.arcgis.com/javascript/latest/references/core/geometry/Polygon/) is the only supported geometries type.
   */
  geometries?: ReadonlyArrayOrCollection<PolygonProperties>;
}

/**
 * A SceneFilter defines parameters for setting a client-side spatial filter on a [SceneLayer.filter](https://developers.arcgis.com/javascript/latest/references/core/layers/SceneLayer/#filter).
 *
 * It is possible to define a collection of polygon [geometries](https://developers.arcgis.com/javascript/latest/references/core/layers/support/SceneFilter/#geometries) which will mask out different parts of the layer. The [spatialRelationship](https://developers.arcgis.com/javascript/latest/references/core/layers/support/SceneFilter/#spatialRelationship) attribute defines if the content inside or outside of the polygons should be masked.
 *
 * This filter is also persisted in [WebScenes](https://developers.arcgis.com/javascript/latest/references/core/WebScene/) and when saving the [SceneLayer.filter](https://developers.arcgis.com/javascript/latest/references/core/layers/SceneLayer/#filter).
 *
 * @since 4.24
 * @see [Sample - Filter SceneLayer with SceneFilter](https://developers.arcgis.com/javascript/latest/sample-code/layers-scenelayer-scene-masking/)
 */
export default class SceneFilter extends JSONSupport {
  constructor(properties?: SceneFilterProperties);
  /**
   * The geometries to apply to the spatial filter.
   *
   * The spatial relationship as specified by [spatialRelationship](https://developers.arcgis.com/javascript/latest/references/core/layers/support/SceneFilter/#spatialRelationship) will indicate how the
   * geometry should be used to filter features. Multiple, overlapping geometries are applied as the union of their
   * spatialRelationship operation. For multiple rings within a polygon the even odd rule is used to determine whether
   * a point is inside.
   *
   * > [!WARNING]
   * >
   * > **Known Limitations**
   * >
   * > [Polygon](https://developers.arcgis.com/javascript/latest/references/core/geometry/Polygon/) is the only supported geometries type.
   */
  get geometries(): Collection<Polygon>;
  set geometries(value: ReadonlyArrayOrCollection<PolygonProperties>);
  /**
   * The type of masking to perform.
   *
   * Illustration | Modification | Description
   * ------|------------|--------
   * <img src="https://developers.arcgis.com/javascript/latest/assets/references/core/layers/modification-clip.png" alt="filter-type-disjoint" style="width:100px;"/>| <b>disjoint</b> - removes selected area | Remove portions of the scene layer. Use a polygon and don't draw the parts inside that polygon. For example to add another layer which shows a new development for that part of the city.
   * <img src="https://developers.arcgis.com/javascript/latest/assets/references/core/layers/modification-mask.png" alt="filter-type-contains" style="width:100px;"/> | <b>contains</b> - displays only selected area |  Define an area of interest. Use a polygon and draw only parts of the scene layer inside that polygon. For example, to show only a portion of a scene layer within the boundaries of a city.
   *
   * @default "disjoint"
   * @see [SceneLayer.filter](https://developers.arcgis.com/javascript/latest/references/core/layers/SceneLayer/#filter)
   */
  accessor spatialRelationship: SpatialRelationship;
  /**
   * Creates a deep clone of the SceneFilter object.
   *
   * @returns A new instance of a SceneFilter object equal to the object used to call `.clone()`.
   */
  clone(): SceneFilter;
}

export type SpatialRelationship = "disjoint" | "contains";